// Extract delegation data from webhook
const body = $input.first().json.body;
const prompt = body.prompt || '';
const category = body.category || 'OTHER';
const priority = body.priority || 'NORMAL';
const taskId = body.task_id || '';
const firmId = body.firm_id || '';

// Route to appropriate agent based on category
const ROUTES = {
  'MOTION': 'CTO',
  'DISCOVERY': 'Deep_Crawler',
  'CLIENT_INTAKE': 'CX_Strategist',
  'BILLING': 'CFO',
  'RESEARCH': 'Researcher',
  'FILING': 'Compliance_Officer',
  'CORRESPONDENCE': 'CMO',
  'REVIEW': 'The_Critic',
  'CONTRACT': 'CTO',
  'COMPLIANCE': 'Compliance_Officer',
  'OTHER': 'CEO'
};

const targetAgent = ROUTES[category] || 'CEO';

// SLA mapping
const SLA = {
  'URGENT': 4,
  'HIGH': 24,
  'NORMAL': 72,
  'LOW': 168
};

return [{
  json: {
    task_id: taskId,
    firm_id: firmId,
    prompt: prompt,
    category: category,
    priority: priority,
    target_agent: targetAgent,
    sla_hours: SLA[priority] || 72,
    escalate_to_ceo: priority === 'URGENT',
    routed_at: new Date().toISOString()
  }
}];

// Log urgent escalation to CEO
const data = $input.first().json;
return [{
  json: {
    ...data,
    escalation: {
      type: 'URGENT_CEO_COPY',
      reason: `Urgent ${data.category} task requires CEO visibility`,
      notified: ['CEO', data.target_agent],
      escalated_at: new Date().toISOString()
    }
  }
}];

// Standard routing - no escalation needed
const data = $input.first().json;
return [{
  json: {
    ...data,
    escalation: null,
    routing_status: 'DIRECT'
  }
}];

// Merge and finalize routing decision
const data = $input.first().json;

const result = {
  status: 'routed',
  task_id: data.task_id,
  assigned_agent: data.target_agent,
  category: data.category,
  priority: data.priority,
  sla_hours: data.sla_hours,
  escalation: data.escalation,
  workflow: 'legal-delegation-router',
  completed_at: new Date().toISOString()
};

return [{ json: result }];
